533	template<typename T>
534	void ParallelGpt<T>::forward(std::vector<Tensor>*        output_tensors,
535	                             const std::vector<Tensor>*  input_tensors,
536	                             const ParallelGptWeight<T>* gpt_weights)
537	{
538	    // input_tensors:
539	    //      input_ids [batch_size, max_input_length]
540	    //      input_lengths [batch_size]
541	    //      max_output_seq_len [1] on cpu
542	
543	    // output_tensors:
544	    //      output_ids [batch_size, beam, max_output_seq_len]
545	    //      sequence_length [batch_size, beam]
546	    //      output_log_probs [batch_size, beam, request_output_seq_len], must be float*.
547	    //          It leads to additional computing cost. If we don't need this result, please put nullptr
548	    //      cum_log_probs [batch_size, beam], must be float*, optional
549	    //          The cumulative log probability of generated sequences. It leads additional computing cost.
550	
551	    // Step is from max_input_length ~ max_output_seq_len,
552	    // When step = k,  we put output ids and caches at step k, and the sequence_length would be k - 1 before
553	    // complete this step.
554	    // When there is no input_ids, put the start token at step 0 of output_ids_buf_. After forward, only copy
555	    // the step 1 ~ max_output_seq_len of output_ids_buf_ to output_tensors->at(0).data
556	
557	    std::unordered_map<std::string, Tensor> input_tensors_map{{"input_ids", input_tensors->at(0)},
558	                                                              {"input_lengths", input_tensors->at(1)},
559	                                                              {"max_output_seq_len", input_tensors->at(2)}};
560	    input_tensors_map.insert({"random_seed", {MEMORY_CPU, TYPE_INT32, {1}, &random_seed_}});
561	    input_tensors_map.insert({"runtime_top_k", {MEMORY_CPU, TYPE_UINT32, {1}, &top_k_}});
562	    input_tensors_map.insert({"runtime_top_p", {MEMORY_CPU, TYPE_FP32, {1}, &top_p_}});
563	
564	    std::unordered_map<std::string, Tensor> output_tensors_map{{"output_ids", output_tensors->at(0)},
565	                                                               {"sequence_length", output_tensors->at(1)},
566	                                                               {"output_log_probs", output_tensors->at(2)}};
567	    if (output_tensors->size() > 3) {
568	        output_tensors_map.insert({"cum_log_probs", output_tensors->at(4)});
569	    }
570	    forward(&output_tensors_map, &input_tensors_map, gpt_weights);
571	}
572	
573	template<typename T>
574	void ParallelGpt<T>::forward(std::unordered_map<std::string, Tensor>*       output_tensors,
575	                             const std::unordered_map<std::string, Tensor>* input_tensors,
576	                             const ParallelGptWeight<T>*                    gpt_weights)
577	{
578	    // input_tensors:
579	    //      input_ids [batch_size, max_input_length]
580	    //      input_lengths [batch_size]
581	    //      input_lengths_h [batch_size] on cpu, optional
582	    //      prompt_learning_task_name_ids [batch_size] on cpu
583	    //      output_seq_len [batch_size] on cpu
584	    //      stop_words_list [batch_size, 2, stop_words_length], optional
585	    //      bad_words_list [2, bad_words_length] or [batch_size, 2, bad_words_length], optional
586	    //      start_id [batch_size] on cpu, optional
587	    //      end_id [batch_size] on cpu, optional
588	    //      runtime_top_k [1] or [batch_size] on cpu, optional, uint.
589	    //      runtime_top_p [1] or [batch_size] on cpu, optional, float.
590	    //      beam_search_diversity_rate [1] or [batch_size] on cpu, optional, float.
591	    //      temperature [1] or [batch_size] on cpu, optional, float.
592	    //      len_penalty [1] or [batch_size] on cpu, optional, float.
593	    //      repetition_penalty [1] or [batch_size] on cpu, optional, float.
594	    //      presence_penalty [1] or [batch_size] on cpu, optional, float.
595	    //          Only one of repetition and presence penalties is allowed.
596	    //      min_length [1] or [batch_size] on cpu, optional, int
597	    //      random_seed [1] or [batch_size] on cpu, optional, unsigned long long int.
598	    //      request_prompt_lengths [batch_size], optional
599	    //      request_prompt_lengths_h [batch_size], cpu, optional
600	    //      request_prompt_embedding [batch_size, max_prompt_length, hidden_units], float, optional
601	    //      request_prompt_type [batch_size], int, optional
602	    //      is_return_context_cum_log_probs [1] on cpu, bool, optional
603	    //      session_len [1] on cpu, uint32, optional
604	    //      memory_len [1] on cpu, uint32, optional
605	    //      continue_gen [1] on cpu, bool, optional
606	    //      is_return_context_embeddings [1] on cpu, bool, optional
607	    //      top_p_decay [batch_size] on gpu, float, optional
608	    //      top_p_min [batch_size] on gpu, float, optional
609	    //      top_p_reset_ids [batch_size] on gpu, uint32, optional
610	
611	    // output_tensors:
612	    //      output_ids [batch_size, beam_width, max_output_seq_len]
613	    //      sequence_length [batch_size, beam_width]
614	    //      response_input_lengths [batch_size, beam_width], optional
615	    //      output_log_probs [batch_size, beam_width, request_output_seq_len], must be float*.
616	    //          optional. It leads to additional computing cost. If we don't need this result, don't put it.
617	    //      cum_log_probs [batch_size, beam_width], must be float*. optional.
618	    //          The cumulative log probability of generated sequences. It may lead to additional computing cost.
619	    //      context_embeddings [batch_size, hidden_units], must be float*, optional
620	
621	    // Step is from max_input_length ~ max_output_seq_len,
622	    // When step = k,  we put output ids and caches at step k, and the sequence_length would be k - 1 before
623	    // complete this step.
624	    // When there is no input_ids, put the start token at step 0 of output_ids_buf_. After forward, only copy
625	    // the step 1 ~ max_output_seq_len of output_ids_buf_ to output_tensors->at(0).data
626	
627	    FT_LOG_DEBUG("%s start", __PRETTY_FUNCTION__);
628	    FT_CHECK_WITH_INFO(input_tensors->size() >= 3, "input_tensors->size() >= 3");
629	    FT_CHECK_WITH_INFO(output_tensors->size() >= 2, "output_tensors->size() >= 2");
630	    FT_CHECK(input_tensors->at("input_ids").shape.size() == 2);
631	    FT_CHECK(input_tensors->at("input_lengths").shape.size() == 1);
632	    FT_CHECK(input_tensors->find("output_seq_len") != input_tensors->end()
633	             && input_tensors->at("output_seq_len").shape.size() == 1);
634	    FT_CHECK(output_tensors->at("output_ids").shape.size() == 3);
635	    FT_CHECK(output_tensors->at("sequence_length").shape.size() == 2);
636	    FT_CHECK_WITH_INFO(input_tensors->at("input_ids").shape[0] == output_tensors->at("output_ids").shape[0],
637	                       "input_tensors->at(\"input_ids\").shape[0] == output_tensors->at(\"output_ids\").shape[0]");
638	
639	    // Used when inputs do not contain random_seed
640	    const size_t batch_size = output_tensors->at("output_ids").shape[0];
641	    const size_t beam_width = output_tensors->at("output_ids").shape[1];
642	    FT_CHECK_WITH_INFO(output_tensors->count("cum_log_probs") == 0
643	                           || output_tensors->at("cum_log_probs").size() == batch_size * beam_width,
644	                       "The shape of cum_log_probs should match with batch_size x beam_width if provided.");
645	    int max_input_length = input_tensors->at("input_ids").shape[1];
646	
647	    bool       continue_gen = input_tensors->find("continue_gen") != input_tensors->end() ?
648	                                  input_tensors->at("continue_gen").getVal<bool>() :
649	                                  false;
650	    const bool is_return_context_embeddings =
651	        input_tensors->find("is_return_context_embeddings") != input_tensors->end()
652	        && input_tensors->at("is_return_context_embeddings").getVal<bool>();
653	    if (is_return_context_embeddings) {
654	        FT_CHECK_WITH_INFO(output_tensors->find("context_embeddings") != output_tensors->end(),
655	                           "When requesting context embeddings, a context embeddings output tensors must be provided");
656	    }
657	
658	    const int initial_step    = continue_gen ? step_ : 0;
659	    int       max_context_len = max_input_length + initial_step;
660	
661	    // NOTE: the input already contains the p/prompt-tunning tokens ids for p/prompt tuning task
662	    // prompt_learning_task_name_ids are used by both p/prompt-tunning and prefix_prompt task
663	    const int* prompt_learning_task_name_ids =
664	        input_tensors->count("prompt_learning_task_name_ids") ?
665	            input_tensors->at("prompt_learning_task_name_ids").getPtr<const int>() :
666	            nullptr;
667	
668	    FT_CHECK_WITH_INFO(
669	        !(prompt_learning_task_name_ids != nullptr
670	          && (prompt_learning_type_ == PromptLearningType::no_prompt
671	              || prompt_learning_type_ == PromptLearningType::soft_prompt)),
672	        "prompt_learning_type is prefix_prompt either p_prompt_tuning when prompt_learning_task_name_ids are provided.");
673	
674	    PromptLearningType request_prompt_type = PromptLearningType::no_prompt;
675	    int                valid_prompt_inputs = input_tensors->count("request_prompt_type")
676	                              + input_tensors->count("request_prompt_lengths")
677	                              + input_tensors->count("request_prompt_embedding");
678	
679	    if (valid_prompt_inputs == 3) {
680	        request_prompt_type = static_cast<PromptLearningType>(input_tensors->at("request_prompt_type").getVal<int>());
681	        if (prompt_learning_task_name_ids != nullptr) {
682	            FT_LOG_INFO("Apply prompt embedding from input, will ignore task name ids");
683	        }
684	    }
685	    else if (valid_prompt_inputs > 0) {
686	        FT_LOG_WARNING(
687	            "Prompts not applied: request_prompt_embedding, request_prompt_lengths, request_prompt_type are all needed!");
688	    }
689	    if (request_prompt_type == PromptLearningType::prefix_prompt) {
690	        FT_LOG_WARNING("Request prompt doesn't support prefix prompt currently!");
691	    }
692	
693	    // whether or not use prompt embeddings from the request.
694	    // If true, staticlly loaded prompts weights during model loading and task name ids will be ignored
695	    bool use_request_p_prompt_embedding = request_prompt_type == PromptLearningType::p_prompt_tuning;
696	    int  max_request_p_prompt_length =
697	        use_request_p_prompt_embedding ? input_tensors->at("request_prompt_embedding").shape[1] : 0;
698	    // p_prompt tuning: input and prompt are concatnenated (not separate),
699	    const uint32_t* input_lengths_h = input_tensors->count("input_lengths_h") ?
700	                                          input_tensors->at("input_lengths_h").getPtr<const uint32_t>() :
701	                                          nullptr;
702	
703	    size_t max_input_without_prompt_length = max_context_len;
704	    if (use_request_p_prompt_embedding && input_lengths_h != nullptr
705	        && input_tensors->count("request_prompt_lengths_h")) {
706	
707	        const uint32_t* request_prompt_lengths_h =
708	            input_tensors->at("request_prompt_lengths_h").getPtr<const uint32_t>();
709	        max_input_without_prompt_length = input_lengths_h[0] - request_prompt_lengths_h[0];
710	        for (int bs_id = 1; bs_id < batch_size; ++bs_id) {
711	            max_input_without_prompt_length = std::max(size_t(input_lengths_h[bs_id] - request_prompt_lengths_h[bs_id]),
712	                                                       max_input_without_prompt_length);
713	        }
714	    }
715	
716	    has_prefix_prompt_ =
717	        (prompt_learning_task_name_ids != nullptr && prompt_learning_type_ == PromptLearningType::prefix_prompt);
718	    has_p_prompt_tuning_ =
719	        prompt_learning_task_name_ids != nullptr && prompt_learning_type_ == PromptLearningType::p_prompt_tuning
720	        || use_request_p_prompt_embedding;
721	    bool use_loaded_p_prompt_embedding = has_p_prompt_tuning_ && !use_request_p_prompt_embedding;
722	    has_prefix_soft_prompt_            = request_prompt_type == PromptLearningType::soft_prompt;
723	
724	    // NOTE: soft prompt
725	    FT_CHECK_WITH_INFO(!(has_prefix_soft_prompt_ && continue_gen),
726	                       "Interactive Generations cannot work with prefix_soft_prompt !");
727	    const size_t max_prefix_soft_prompt_length =
728	        has_prefix_soft_prompt_ ? input_tensors->at("request_prompt_embedding").shape[1] : 0;
729	    const size_t limit_len_offset = max_prefix_soft_prompt_length + (max_input_length == 0 ? 1 : 0);
730	    const size_t gen_len          = input_tensors->at("output_seq_len").max<uint32_t>() + limit_len_offset;
731	
732	    size_t session_len = 0;
733	    if (continue_gen) {
734	        session_len = session_len_;  // Record the size of allocated buffer in previous round.
735	    }
736	    else if (input_tensors->find("session_len") != input_tensors->end()) {
737	        session_len = input_tensors->at("session_len").getVal<uint32_t>();  // Use for allocate buffer in first round.
738	    }
739	    else {
740	        session_len = gen_len;  // When the interactive generation mode is disabled.
741	    }
742	    session_len_ = session_len;
743	    FT_CHECK_WITH_INFO(
744	        gen_len + initial_step <= session_len,
745	        fmtstr("Session size too low (%d) vs. total output size (%d)", session_len, gen_len + initial_step));
746	    size_t memory_len = 0;
747	    if (continue_gen) {
748	        memory_len = memory_len_;  // Record the size of allocated buffer in previous round.
749	    }
750	    else if (input_tensors->find("memory_len") != input_tensors->end()) {
751	        memory_len = input_tensors->at("memory_len").getVal<uint32_t>();  // Use for allocate buffer in first round.
752	    }
753	    else {
754	        memory_len = session_len;  // When the interactive generation mode is disabled.
755	    }
756	    memory_len_ = memory_len;
757	    /* TODO: could remove this constraint by changing how context decoder operates */
758	    FT_CHECK_WITH_INFO(max_input_length <= memory_len,
759	                       fmtstr("Memory size too low (%d) vs. input length (%d)", memory_len, max_input_length));
760	
761	    if (memory_len < session_len) {
762	        FT_LOG_WARNING("memory_len (%d) is less than session_len (%d). "
763	                       "Note that this reduces the memory cost of k/v cache, but may hurt the accuracy.",
764	                       memory_len,
765	                       session_len);
766	    }
767	    else if (memory_len > session_len) {
768	        FT_LOG_WARNING("memory_len (%d) is larger than session_len (%d). "
769	                       "This may lead to additional memory cost. Suggest to use smaller memory_len.",
770	                       memory_len,
771	                       session_len);
772	    }
773	
774	    if (gpt_variant_params_.has_positional_encoding && session_len_ > gpt_weights->getMaxSeqLen()) {
775	        FT_LOG_ERROR("The session_len_ (%d) of request is longer than max_seq_len (%d) of embedding table."
776	                     " This is a invalid input. Setting the session_len_ to %d.",
777	                     session_len_,
778	                     gpt_weights->getMaxSeqLen(),
779	                     gpt_weights->getMaxSeqLen());
780	        session_len_ = gpt_weights->getMaxSeqLen();
781	    }
782	
783	    const bool is_return_context_cum_log_probs = input_tensors->count("is_return_context_cum_log_probs") > 0
784	                                                 && input_tensors->at("is_return_context_cum_log_probs").getVal<bool>();
785	    if (is_return_context_cum_log_probs) {
786	        FT_CHECK_WITH_INFO(output_tensors->count("cum_log_probs")
787	                               && output_tensors->at("cum_log_probs").data != nullptr,
788	                           "`cum_log_probs` must be provided in `output_tensors` in order to enable "
789	                           "the cumulative log probability computation of input contexts.");
790	    }
791	
792	    PUSH_RANGE("buffer allocation");
793	    if (!continue_gen) {
794	        allocateBuffer(batch_size,
795	                       beam_width,
796	                       session_len,
797	                       memory_len,
798	                       max_input_length + max_prefix_soft_prompt_length,
799	                       is_return_context_cum_log_probs);
800	        sync_check_cuda_error();
801	    }
802	    setSeqLimitLen(seq_limit_len_, input_tensors->at("output_seq_len"), limit_len_offset, batch_size);
803	    POP_RANGE;
804	
805	    const DataType       data_type      = getTensorType<T>();
806	    const cudaDataType_t gemm_data_type = getCudaDataType<T>();
807	
808	    const std::vector<size_t> self_k_cache_shape = {num_layer_ / pipeline_para_.world_size_,
809	                                                    batch_size * beam_width,
810	                                                    local_head_num_,
811	                                                    size_per_head_ / (16 / sizeof(T)),
812	                                                    memory_len,
813	                                                    16 / sizeof(T)};
814	    const std::vector<size_t> self_v_cache_shape = {
815	        num_layer_ / pipeline_para_.world_size_, batch_size * beam_width, local_head_num_, memory_len, size_per_head_};
816	
817	    {
818	        TensorMap input_map(*input_tensors);
819	
820	        PUSH_RANGE("dynamic decode setup");
821	        dynamic_decode_layer_->setup(batch_size, beam_width, &input_map);
822	        handleOptArg(&input_map, "start_id", start_ids_buf_, start_id_, batch_size);
823	        handleOptArg(&input_map, "end_id", end_ids_buf_, end_id_, batch_size);
824	        POP_RANGE;
825	    }
826	
827	    if (gpt_variant_params_.use_attention_linear_bias) {
828	        PUSH_RANGE("build alibi slopes");
829	        invokeBuildAlibiSlopes(linear_bias_slopes_, head_num_, stream_);
830	        POP_RANGE;
831	    }
832	
833	    if (continue_gen) {
834	        PUSH_RANGE("input tiling and init");
835	        invokeTileGptInputs(tiled_input_ids_buf_,
836	                            tiled_input_lengths_buf_,
837	                            input_tensors->at("input_ids").getPtr<int>(),
838	                            input_tensors->at("input_lengths").getPtr<const int>(),
839	                            batch_size,
840	                            beam_width,
841	                            max_input_length,
842	                            stream_);
843	        invokePlusScalar(tiled_input_lengths_buf_, initial_step, batch_size * beam_width, stream_);
844	        sync_check_cuda_error();
845	        invokeDecodingInitialize(finished_buf_,
846	                                 sequence_lengths_,
847	                                 nullptr,
848	                                 cum_log_probs_,
849	                                 start_ids_buf_,
850	                                 batch_size,
851	                                 beam_width,
852	                                 initial_step - 1,
853	                                 stream_);
854	        invokeTransposeAxis01(output_ids_buf_ + initial_step * batch_size * beam_width,
855	                              tiled_input_ids_buf_,
856	                              batch_size * beam_width,
857	                              max_input_length,
858	                              1,
859	                              stream_);
860	        POP_RANGE;
861	    }
862	    else {
863	        // TODO(bhsueh) Initilaize them in one kernel
864	        // initialize the output ids and parent ids
865	        PUSH_RANGE("initialize output and parent ids");
866	        cudaMemsetAsync(output_ids_buf_, 0, sizeof(int) * batch_size * beam_width * session_len, stream_);
867	        cudaMemsetAsync(parent_ids_buf_, 0, sizeof(int) * batch_size * beam_width * session_len, stream_);
868	        cudaMemsetAsync(tiled_masked_tokens_, false, sizeof(bool) * batch_size * beam_width * memory_len, stream_);
869	        cudaMemsetAsync(tiled_total_padding_count_, 0, sizeof(int) * batch_size * beam_width, stream_);
870	        if (beam_width > 1) {
871	            cudaMemsetAsync(cache_indirections_[0], 0, 2 * sizeof(int) * batch_size * beam_width * memory_len, stream_);
872	        }
873	        sync_check_cuda_error();
874	        POP_RANGE;
875	
876	        PUSH_RANGE("padded embedding kernel init");
877	        if (vocab_size_ == vocab_size_padded_) {
878	            padded_embedding_kernel_ptr_ = gpt_weights->post_decoder_embedding.kernel;
879	        }
880	        else {
881	            cudaAutoCpy(padded_embedding_kernel_,
882	                        gpt_weights->post_decoder_embedding.kernel,
883	                        vocab_size_ * hidden_units_,
884	                        stream_);
885	            sync_check_cuda_error();
886	        }
887	        POP_RANGE;
888	
889	        int  compact_size;
890	        bool use_shared_contexts = (shared_contexts_ratio_ > 0.0f) && (max_input_length >= 1) && (batch_size > 1);
891	        PUSH_RANGE("find context dups");
892	        if (use_shared_contexts) {
893	            invokeFindContextDups(shared_contexts_idx_,
894	                                  batch_to_compact_idx_,
895	                                  compact_idx_,
896	                                  compact_size_,
897	                                  input_tensors->at("input_ids").getPtr<int>(),
898	                                  batch_size,
899	                                  beam_width,
900	                                  max_input_length,
901	                                  stream_);
902	            cudaD2Hcpy(&compact_size, compact_size_, 1);
903	            use_shared_contexts = compact_size <= shared_contexts_ratio_ * batch_size;
904	            sync_check_cuda_error();
905	        }
906	        POP_RANGE;
907	
908	        // NOTE: p/prompt-tuning process here (lookup prompt embedding tables by task name ids)
909	        // get p/prompt-tuning weight for each batch --> shape [batch, beam_width]
910	        // --> ptrs with shape [prompt_len, hidden_size]
911	        std::vector<const T*> p_prompt_tuning_batch_ptrs;
912	        std::vector<int>      p_prompt_tuning_lengths;
913	        PUSH_RANGE("prompt embedding lookup");
914	        if (use_loaded_p_prompt_embedding) {
915	            for (int bs_id = 0; bs_id < batch_size; ++bs_id) {
916	                int                      task_id              = prompt_learning_task_name_ids[bs_id];
917	                std::pair<const T*, int> p_prompt_tuning_pair = {};
918	                bool                     valid_task_name_id   = task_id < gpt_weights->prompt_learning_table.size();
919	                if (valid_task_name_id) {
920	                    p_prompt_tuning_pair = gpt_weights->prompt_learning_table.at(task_id);
921	                }
922	                else {
923	                    // don't throw oor in case of model server failing
924	                    FT_LOG_ERROR("p_prompt_tuning_weights not found for task id: " + std::to_string(task_id)
925	                                 + "\n return with invalid output tensors");
926	                    return;
927	                }
928	                if (input_lengths_h != nullptr) {
929	                    if (bs_id == 0) {
930	                        max_input_without_prompt_length = input_lengths_h[bs_id] - p_prompt_tuning_pair.second;
931	                    }
932	                    else {
933	                        max_input_without_prompt_length =
934	                            std::max(size_t(input_lengths_h[bs_id] - p_prompt_tuning_pair.second),
935	                                     max_input_without_prompt_length);
936	                    }
937	                }
938	                for (int bw_id = 0; bw_id < beam_width; ++bw_id) {
939	                    // only weight ptrs needed here
940	                    p_prompt_tuning_batch_ptrs.push_back(p_prompt_tuning_pair.first);
941	                    p_prompt_tuning_lengths.push_back(p_prompt_tuning_pair.second);
942	                }
943	            }
944	
945	            cudaAutoCpy(
946	                prompt_learning_weight_batch_, p_prompt_tuning_batch_ptrs.data(), batch_size * beam_width, stream_);
947	
948	            cudaAutoCpy(tiled_prompt_lengths_buf_, p_prompt_tuning_lengths.data(), batch_size * beam_width, stream_);
949	
950	            sync_check_cuda_error();
951	        }
952	        POP_RANGE;
953	
954	        // handle first step
955	        if (has_p_prompt_tuning_ || has_prefix_prompt_ || has_prefix_soft_prompt_ || max_input_length > 1) {
956	            PUSH_RANGE("input tiling and init");
957	            invokeTileGptPromptInputs(tiled_input_ids_buf_,
958	                                      tiled_input_lengths_buf_,
959	                                      use_request_p_prompt_embedding ? tiled_prompt_lengths_buf_ : nullptr,
960	                                      input_tensors->at("input_ids").getPtr<int>(),
961	                                      input_tensors->at("input_lengths").getPtr<const int>(),
962	                                      use_request_p_prompt_embedding ?
963	                                          input_tensors->at("request_prompt_lengths").getPtr<const int>() :
964	                                          nullptr,
965	                                      batch_size,
966	                                      beam_width,
967	                                      max_input_length,
968	                                      stream_);
969	            sync_check_cuda_error();
970	            POP_RANGE;
971	
972	            if (has_prefix_soft_prompt_) {
973	                PUSH_RANGE("input id embedding lookup");
974	                inputIdsEmbeddingLookupPosEncodingSoftPromptParam<T> param;
975	                param.from_tensor                   = context_decoder_input_buf_;
976	                param.output_ids                    = output_ids_buf_;
977	                param.input_lengths                 = tiled_input_lengths_buf_;
978	                param.embedding_table               = gpt_weights->pre_decoder_embedding_table;
979	                param.pos_table                     = gpt_weights->position_encoding_table;
980	                param.prefix_soft_prompt_embedding  = input_tensors->at("request_prompt_embedding").getPtr<float>();
981	                param.prefix_soft_prompt_lengths    = input_tensors->at("request_prompt_lengths").getPtr<int>();
982	                param.input_ids                     = tiled_input_ids_buf_;
983	                param.start_step                    = 1;
984	                param.max_input_length              = max_input_length;
985	                param.max_prefix_soft_prompt_length = max_prefix_soft_prompt_length;
986	                param.batch_size                    = batch_size;
987	                param.beam_width                    = beam_width;
988	                param.hidden_units                  = hidden_units_;
989	                param.stream                        = stream_;
990	
991	                invokeInputIdsEmbeddingLookupPosEncodingSoftPrompt(param);
992	                sync_check_cuda_error();
993	                POP_RANGE;
994	
995	                max_input_length += max_prefix_soft_prompt_length;  // view soft_prompt as input
996	                max_context_len += max_prefix_soft_prompt_length;
997	            }
998	            else {
999	                // NOTE: add prompt embeddings here (for p/prompt tuning)
1000	                PUSH_RANGE("input id embedding lookup");
