1480	                            output_tensors->count("output_log_probs") > 0
1481	                                    && output_tensors->at("output_log_probs").data != nullptr ?
1482	                                output_log_probs_buf_ :
1483	                                nullptr}},
1484	                    {"parent_ids", Tensor{MEMORY_GPU, TYPE_INT32, {gen_len, batch_size, beam_width}, parent_ids_buf_}},
1485	                    {"sequence_length", Tensor{MEMORY_GPU, TYPE_INT32, {batch_size * beam_width}, sequence_lengths_}},
1486	                    {"tgt_cache_indirection",
1487	                     Tensor{MEMORY_GPU,
1488	                            TYPE_INT32,
1489	                            {local_batch_size, beam_width, memory_len},
1490	                            cache_indirections_[tgt_indir_idx] + id_offset * memory_len}},
1491	                    {"should_stop", Tensor{MEMORY_CPU, TYPE_BOOL, {1}, &subbatch_should_stop}}};
1492	                for (auto t = output_tensors->begin(); t != output_tensors->end(); ++t) {
1493	                    // Handle exceptions.
1494	                    if (t->first == "cum_log_probs" || t->first == "output_log_probs") {
1495	                        continue;
1496	                    }
1497	                    dynamic_decode_output_tensors.insert(*t);
1498	                }
1499	
1500	                PUSH_RANGE("result sampling and stop check");
1501	                dynamic_decode_layer_->forward(&dynamic_decode_output_tensors, &dynamic_decode_input_tensors);
1502	                generation_should_stop &= subbatch_should_stop;
1503	                microbatch_should_stop_[ite] = subbatch_should_stop;
1504	                POP_RANGE;
1505	            }
1506	            else {
1507	                // for other ranks, they cannot update generation_should_stop by DynamicDecode, set to false directly;
1508	                generation_should_stop &= microbatch_should_stop_[ite];
1509	            }
1510	
1511	            PUSH_RANGE("result communication");
1512	            // send results to other rank
1513	            if (fill_caches_only) {
1514	                invokePlusScalar(sequence_lengths_, 1, batch_size * beam_width, stream_);
1515	            }
1516	
1517	            // When pipeline parallelism is enabled (pipeline_para_.world_size_ > 1), last rank needs to send updates
1518	            // to other ranks.
1519	            if (step_ < gen_len - 1 && pipeline_para_.world_size_ > 1
1520	                && pipeline_para_.rank_ == pipeline_para_.world_size_ - 1) {
1521	                ftNcclGroupStart();
1522	                for (int i = 0; i < pipeline_para_.world_size_ - 1; i++) {
1523	                    // send updated sequence_length_ to other rank
1524	                    ftNcclSend(
1525	                        sequence_lengths_ + id_offset, local_batch_size * beam_width, i, pipeline_para_, stream_);
1526	
1527	                    // send updated microbatch_should_stop_
1528	                    ftNcclSend(microbatch_should_stop_ + ite, 1, i, pipeline_para_, stream_);
1529	
1530	                    // send updated cache_indirections
1531	                    if (beam_width > 1) {
1532	                        ftNcclSend(cache_indirections_[tgt_indir_idx] + id_offset * memory_len,
1533	                                   local_batch_size * beam_width * memory_len,
1534	                                   i,
1535	                                   pipeline_para_,
1536	                                   stream_);
1537	                    }
1538	                }
1539	
1540	                // for ids of next step, only need to send updated ids to first rank
1541	                ftNcclSend(output_ids_buf_ + step_ * batch_size * beam_width + id_offset,
1542	                           local_batch_size * beam_width,
1543	                           0,
1544	                           pipeline_para_,
1545	                           stream_);
1546	
1547	                ftNcclGroupEnd();
1548	                // throw errors when detected
1549	                ftNcclStreamSynchronize(tensor_para_, pipeline_para_, stream_);
1550	                sync_check_cuda_error();
1551	            }
1552	            POP_RANGE;
1553	        }
1554	
1555	        if (token_generated_cb_ && step_ + 1 < (int)gen_len) {
1556	            setOutputTensors(
1557	                output_tensors, input_tensors, gen_len, session_len, max_context_len, max_input_without_prompt_length);
1558	            sendTensorsToFirstPipelineNode(output_tensors, input_tensors);
1559	
1560	            if (pipeline_para_.rank_ == 0 && tensor_para_.rank_ == 0) {
1561	                token_generated_cb_(output_tensors, token_generated_ctx_);
1562	            }
1563	        }
1564	
1565	        if (step_ == initial_step + max_input_length) {
1566	            /* We have just finished processing input: update the padding count:
1567	             * total_padding_count += (max_input_length - input_lengths) */
1568	            PUSH_RANGE("Update padding count");
1569	            invokeUpdatePaddingCount(tiled_total_padding_count_,
1570	                                     input_tensors->at("input_lengths").getPtr<int>(),
1571	                                     max_input_length,
1572	                                     batch_size,
1573	                                     beam_width,
1574	                                     stream_);
1575	            POP_RANGE;
1576	        }
1577	
1578	        if (generation_should_stop) {
1579	            break;
1580	        }
1581	
1582	        POP_RANGE;
1583	    }
1584	    PUSH_RANGE("communicate tensors");
1585	    setOutputTensors(
1586	        output_tensors, input_tensors, gen_len, session_len, max_context_len, max_input_without_prompt_length);
1587	    sendTensorsToFirstPipelineNode(output_tensors, input_tensors);
1588	    POP_RANGE;
1589	}
1590	
1591	template<typename T>
1592	void ParallelGpt<T>::sendTensorsToFirstPipelineNode(std::unordered_map<std::string, Tensor>*       output_tensors,
1593	                                                    const std::unordered_map<std::string, Tensor>* input_tensors)
1594	{
1595	    if (pipeline_para_.world_size_ == 1) {
1596	        // throw errors when detected
1597	        ftNcclStreamSynchronize(tensor_para_, pipeline_para_, stream_);
1598	        return;
1599	    }
1600	
1601	    const auto pp_rank = pipeline_para_.rank_;
1602	
1603	    ftNcclGroupStart();
1604	    for (auto const& it : *output_tensors) {
1605	        if (it.second.data == nullptr) {
1606	            continue;
1607	        }
1608	
1609	        if (pp_rank == pipeline_para_.world_size_ - 1) {
1610	            ftNcclSend(it.second.getPtr<char>(), it.second.sizeBytes(), 0, pipeline_para_, stream_);
1611	        }
1612	        else if (pp_rank == 0) {
1613	            ftNcclRecv(it.second.getPtr<char>(),
1614	                       it.second.sizeBytes(),
1615	                       pipeline_para_.world_size_ - 1,
1616	                       pipeline_para_,
1617	                       stream_);
1618	        }
1619	    }
1620	    ftNcclGroupEnd();
1621	    // throw errors when detected
1622	    ftNcclStreamSynchronize(tensor_para_, pipeline_para_, stream_);
1623	}
1624	
1625	template<typename T>
1626	void ParallelGpt<T>::setOutputTensors(std::unordered_map<std::string, Tensor>*       output_tensors,
1627	                                      const std::unordered_map<std::string, Tensor>* input_tensors,
1628	                                      const size_t                                   gen_len,
1629	                                      const size_t                                   session_len,
1630	                                      const size_t                                   max_context_len,
1631	                                      const size_t                                   max_input_without_prompt_length)
1632	{
1633	    PUSH_RANGE("Resolve output tensors");
1634	    if (pipeline_para_.rank_ != pipeline_para_.world_size_ - 1) {
1635	        return;
1636	    }
1637	
1638	    const size_t batch_size       = output_tensors->at("output_ids").shape[0];
1639	    const size_t beam_width       = output_tensors->at("output_ids").shape[1];
1640	    int*         sequence_lengths = output_tensors->at("sequence_length").getPtr<int>();
1641	    const size_t max_prefix_soft_prompt_length =
1642	        has_prefix_soft_prompt_ ? input_tensors->at("request_prompt_embedding").shape[1] : 0;
1643	
1644	    cudaAutoCpy(sequence_lengths, sequence_lengths_, output_tensors->at("sequence_length").size(), stream_);
1645	    if (input_tensors->at("input_ids").shape[1] == 0) {
1646	        // TODO: D2D sequence_lenghts
1647	        if (beam_width > 1) {
1648	            // For beam search, do gather_tree
1649	            // take output_parent_ids as inter buffer
1650	            invokeGatherTree(transposed_output_ids_buf_,
1651	                             sequence_lengths_,
1652	                             session_len,
1653	                             batch_size,
1654	                             beam_width,
1655	                             output_ids_buf_ + batch_size * beam_width,
1656	                             parent_ids_buf_ + batch_size * beam_width,
1657	                             end_ids_buf_,
1658	                             stream_);
1659	
1660	            // transpose and take output_parent_ids as inter buffer
1661	            invokeTransposeAxis01(output_tensors->at("output_ids").getPtr<int>(),
1662	                                  transposed_output_ids_buf_,
1663	                                  gen_len - 1,
1664	                                  batch_size * beam_width,
1665	                                  1,
1666	                                  stream_);
1667	        }
1668	        else {
1669	            // For sampling, only copy the results to output_tensor
1670	            invokeTransposeAxis01(output_tensors->at("output_ids").getPtr<int>(),
1671	                                  output_ids_buf_ + batch_size * beam_width,
1672	                                  gen_len - 1,
1673	                                  batch_size * beam_width,
1674	                                  1,
1675	                                  stream_);
1676	        }
1677	    }
1678	    else {
1679	        // For sampling, it is equivalent to all parent ids are 0.
1680	        gatherTreeParam param;
1681	        param.beams = transposed_output_ids_buf_;
1682	        // Remove prompt length if possible
1683	        param.max_sequence_lengths = sequence_lengths;
1684	        // add sequence_length 1 here because the sequence_length of time step t is t - 1
1685	        param.max_sequence_length_final_step = 1;
1686	        // response input lengths (used to slice the ids during postprocessing)
1687	        param.response_input_lengths = output_tensors->count("response_input_lengths") ?
1688	                                           output_tensors->at("response_input_lengths").getPtr<int>() :
1689	                                           nullptr;
1690	        param.max_time               = gen_len;
1691	        param.batch_size             = batch_size;
1692	        param.beam_width             = beam_width;
1693	        param.step_ids               = output_ids_buf_;
1694	        param.parent_ids             = beam_width == 1 ? nullptr : parent_ids_buf_;
1695	        param.end_tokens             = end_ids_buf_;
1696	        param.max_input_length       = max_context_len;
1697	        param.prefix_soft_prompt_lengths =
1698	            has_prefix_soft_prompt_ ? input_tensors->at("request_prompt_lengths").getPtr<int>() : nullptr;
1699	        param.input_lengths                   = tiled_input_lengths_buf_;
1700	        param.p_prompt_tuning_prompt_lengths  = has_p_prompt_tuning_ ? tiled_prompt_lengths_buf_ : nullptr;
1701	        param.max_input_without_prompt_length = max_input_without_prompt_length;
1702	        param.max_prefix_soft_prompt_length   = max_prefix_soft_prompt_length;
1703	        param.stream                          = stream_;
1704	        param.output_ids                      = output_tensors->at("output_ids").getPtr<int>();
1705	        // NOTE: need to remove all prompt virtual tokens
1706	        invokeGatherTree(param);
1707	        sync_check_cuda_error();
1708	    }
1709	
1710	    // remove p_prompt virtual tokens and update output tensors shape
1711	    if (has_p_prompt_tuning_) {  // remove p_prompt virtual tokens and update output tensors shape
1712	        output_tensors->at("output_ids").updateShape(2, gen_len - (max_context_len - max_input_without_prompt_length));
1713	    }
1714	
1715	    if ((output_tensors->count("output_log_probs") > 0 && output_tensors->at("output_log_probs").data != nullptr)) {
1716	        invokeTransposeAxis01(output_tensors->at("output_log_probs").getPtr<float>(),
1717	                              output_log_probs_buf_,
1718	                              input_tensors->at("output_seq_len").max<uint32_t>() - max_context_len,
1719	                              batch_size * beam_width,
1720	                              1,
1721	                              stream_);
1722	    }
1723	    // Return the cumulative log probability if requested.
1724	    if (output_tensors->count("cum_log_probs") > 0) {
1725	        Tensor cum_log_probs = output_tensors->at("cum_log_probs");
1726	        FT_CHECK_WITH_INFO(cum_log_probs.size() == batch_size * beam_width,
1727	                           "The shape of cum_log_probs does not match with batch_size x beam_width.");
1728	        cudaAutoCpy(cum_log_probs.getPtr<float>(), cum_log_probs_, cum_log_probs.size(), stream_);
1729	    }
1730	
1731	    if (output_tensors->count("is_finished")) {
1732	        cudaD2Dcpy(
1733	            output_tensors->at("is_finished").getPtr<bool>(), finished_buf_, output_tensors->at("is_finished").size());
1734	    }
1735	    POP_RANGE;
1736	}
1737	
1738	template<typename T>
1739	size_t ParallelGpt<T>::getPipelineParallelRank()
1740	{
1741	    return pipeline_para_.rank_;
