94	void ParallelGptContextDecoder<T>::allocateBuffer(size_t batch_size, size_t seq_len, bool use_shared_contexts)
95	{
96	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
97	    decoder_normed_input_ = reinterpret_cast<T*>(
98	        allocator_->reMalloc(decoder_normed_input_, sizeof(T) * batch_size * seq_len * hidden_units_, false));
99	    self_attn_output_ = reinterpret_cast<T*>(
100	        allocator_->reMalloc(self_attn_output_, sizeof(T) * batch_size * seq_len * hidden_units_, false));
101	    normed_self_attn_output_ = decoder_normed_input_;  // reuse the buffer
102	    // only allocate additionl buffers when has adapters
103	    after_adapter_attn_output_ =
104	        has_adapters_ ? reinterpret_cast<T*>(
105	            allocator_->reMalloc(after_adapter_attn_output_, sizeof(T) * batch_size * seq_len * hidden_units_, false)) :
106	                        self_attn_output_;
107	    decoder_layer_output_ = reinterpret_cast<T*>(
108	        allocator_->reMalloc(decoder_layer_output_, sizeof(T) * batch_size * seq_len * hidden_units_, false));
109	    if (int8_mode_ == 2) {
110	        // dynamic scale
111	        attention_query_dynamic_scale_ = reinterpret_cast<float*>(
112	            allocator_->reMalloc(attention_query_dynamic_scale_, sizeof(float) * batch_size * seq_len, true));
113	        ffn_intermediate_dynamic_scale_ = reinterpret_cast<float*>(
114	            allocator_->reMalloc(ffn_intermediate_dynamic_scale_, sizeof(float) * batch_size * seq_len, true));
115	    }
116	    h_pinned_token_num_ptr_ = (size_t*)allocator_->reMalloc(h_pinned_token_num_ptr_, sizeof(size_t), true, true);
117	    padding_offset_ =
118	        reinterpret_cast<int*>(allocator_->reMalloc(padding_offset_, sizeof(int) * batch_size * seq_len, false));
119	    cu_seqlens_ = reinterpret_cast<int*>(allocator_->reMalloc(cu_seqlens_, sizeof(int) * (batch_size + 1), false));
120	    // for moe
121	    expert_scales_ = reinterpret_cast<T*>(
122	        allocator_->malloc(sizeof(T) * pad_to_multiple_of_16(moe_k_ * batch_size * seq_len), false));
123	    expanded_source_row_to_expanded_dest_row_ = reinterpret_cast<int*>(
124	        allocator_->malloc(sizeof(int) * pad_to_multiple_of_16(moe_k_ * batch_size * seq_len), false));
125	    expert_for_source_row_ = reinterpret_cast<int*>(
126	        allocator_->malloc(sizeof(int) * pad_to_multiple_of_16(moe_k_ * batch_size * seq_len), false));
127	    fc2_result_ = reinterpret_cast<T*>(
128	        allocator_->malloc(sizeof(T) * pad_to_multiple_of_16(moe_k_ * batch_size * seq_len * hidden_units_), false));
129	    adapter_fc2_result_ =
130	        has_adapters_ ? reinterpret_cast<T*>(allocator_->malloc(
131	            sizeof(T) * pad_to_multiple_of_16(moe_k_ * batch_size * seq_len * hidden_units_), false)) :
132	                        nullptr;
133	    is_allocate_buffer_ = true;
134	
135	    if (use_shared_contexts) {
136	        compact_decoder_features_ = reinterpret_cast<T*>(
137	            allocator_->reMalloc(compact_decoder_features_, sizeof(T) * batch_size * seq_len * hidden_units_, false));
138	        compact_attention_mask_ = reinterpret_cast<T*>(
139	            allocator_->reMalloc(compact_attention_mask_, sizeof(T) * batch_size * seq_len * seq_len, false));
140	        compact_input_lengths_ =
141	            reinterpret_cast<int*>(allocator_->reMalloc(compact_input_lengths_, sizeof(int) * batch_size, false));
142	        k_cache_layer_ = reinterpret_cast<T*>(
143	            allocator_->reMalloc(k_cache_layer_, sizeof(T) * batch_size * seq_len * hidden_units_, false));
144	        v_cache_layer_ = reinterpret_cast<T*>(
145	            allocator_->reMalloc(v_cache_layer_, sizeof(T) * batch_size * seq_len * hidden_units_, false));
146	    }
147	}
