185	template<typename T>
186	bool ParallelGptContextDecoder<T>::isValidLayerParallelId(uint l)
187	{
188	    int local_num_layer = (int)(ceil(num_layer_ * 1.0f / pipeline_para_.world_size_));
189	    return l < num_layer_ && (l >= local_num_layer * pipeline_para_.rank_)
190	           && (l < local_num_layer * (pipeline_para_.rank_ + 1));
191	}
192	
193	template<typename T>
194	bool ParallelGptContextDecoder<T>::isFirstLayerParallelId(uint l)
195	{
196	    int local_num_layer = (int)(ceil(num_layer_ * 1.0f / pipeline_para_.world_size_));
197	    return l < num_layer_ && (l == local_num_layer * pipeline_para_.rank_);
198	}
199	
200	template<typename T>
201	bool ParallelGptContextDecoder<T>::isLastLayerParallelId(uint l)
202	{
203	    int local_num_layer = (int)(ceil(num_layer_ * 1.0f / pipeline_para_.world_size_));
204	    return l < num_layer_ && (l == local_num_layer * (pipeline_para_.rank_ + 1) - 1);
205	}
206	
207	template<typename T>
208	int ParallelGptContextDecoder<T>::getFirstLayerParallelId()
209	{
210	    int local_num_layer = (int)(ceil(num_layer_ * 1.0f / pipeline_para_.world_size_));
211	    return local_num_layer * pipeline_para_.rank_;
212	}
