302	template<typename T>
303	void ParallelGptContextDecoder<T>::forward(
304	    TensorMap*                                            output_tensors,
305	    const TensorMap*                                      input_tensors,
306	    const std::vector<ParallelGptDecoderLayerWeight<T>*>* gpt_decoder_layer_weight)
307	{
308	    // input tensors:
309	    //      decoder_input [batch_size, seq_len, hidden_dimension],
310	    //      attention_mask [batch_size, 1, seq_len, seq_len]
311	    //      input_lengths [batch_size]
312	    //      compact_idx [compact_size], optional
313	    //      batch_to_compact_idx [batch_size], optional
314	    //      linear_bias_slopes [head_num], optional
315	
316	    // output tensors:
317	    //      decoder_output [batch_size, seq_len, hidden_dimension],
318	    //      key_cache [num_layer, batch, local_head_num, size_per_head // x, max_seq_len, x]
319	    //      value_cache [num_layer, batch, local_head_num, max_seq_len, size_per_head]
320	    //      last_token_hidden_units [batch_size, hidden_dimension]
321	
322	    // To use layer/pipeline parallelism, we view the shape of 'batch_size' to 'ite * local_batch_size'.
323	    // For example, the shape of decoder_input becomes [ite, batch_size, seq_len, hidden_dimension] during
324	    // computing.
325	
326	    FT_LOG_DEBUG("%s start", __PRETTY_FUNCTION__);
327	    FT_CHECK(input_tensors->isExist("decoder_input"));
328	    FT_CHECK(input_tensors->isExist("attention_mask"));
329	    FT_CHECK(input_tensors->isExist("input_lengths"));
330	    FT_CHECK(output_tensors->isExist("decoder_output"));
331	    FT_CHECK(output_tensors->isExist("key_cache"));
332	    FT_CHECK(output_tensors->isExist("value_cache"));
333	    FT_CHECK(output_tensors->isExist("last_token_hidden_units"));
334	
335	    const bool use_shared_contexts = input_tensors->isExist("compact_idx");
336	    FT_CHECK(!use_shared_contexts || input_tensors->isExist("batch_to_compact_idx"));
337	
338	    Tensor decoder_input_tensor = input_tensors->at("decoder_input");
339	    FT_CHECK(decoder_input_tensor.shape[2] == hidden_units_);
340	
341	    // Request batch size
342	    const size_t request_batch_size = decoder_input_tensor.shape[0];
343	    // Maybe compacted batch size.
344	    const size_t batch_size =
345	        use_shared_contexts ? input_tensors->at("compact_idx").shape[0] : decoder_input_tensor.shape[0];
346	    // Request input length
347	    const size_t seq_len = decoder_input_tensor.shape[1];
348	    // The maximum length of generation.
349	    const size_t max_seq_len = output_tensors->at("value_cache").shape[3];
350	
351	    const DataType data_type = getTensorType<T>();
352	
353	    PUSH_RANGE("buffer allocation");
354	    allocateBuffer(batch_size, seq_len, use_shared_contexts);
355	    POP_RANGE;
356	
357	    PUSH_RANGE("compact inputs");
358	    if (use_shared_contexts) {
359	        invokeCompactInputs(compact_decoder_features_,
360	                            compact_attention_mask_,
361	                            compact_input_lengths_,
362	                            decoder_input_tensor.getPtr<T>(),
363	                            input_tensors->at("attention_mask").getPtr<T>(),
364	                            input_tensors->at("input_lengths").getPtr<int>(),
365	                            input_tensors->at("compact_idx").getPtr<int>(),
366	                            batch_size,
367	                            seq_len,
368	                            hidden_units_,
369	                            stream_);
370	    }
371	    POP_RANGE;
372	
373	    const size_t local_batch_size = getLocalBatchSize(batch_size, seq_len, pipeline_para_.world_size_);
374	    FT_CHECK(batch_size % local_batch_size == 0);
375	    const size_t iteration_num = batch_size / local_batch_size;
376	
377	    Tensor k_cache = output_tensors->at("key_cache");
378	    Tensor v_cache = output_tensors->at("value_cache");
379	
380	    const auto activation_in_type  = int8_mode_ == 2 ? TYPE_INT8 : data_type;
381	    const auto activation_out_type = data_type;
382	
383	    // The resize of the key cache buffer by
384	    //   (local_batch_size, local_head_num, size_per_head // x, max_seq_len, x) where x is constant.
385	    std::vector<size_t> self_k_cache_size(k_cache.shape.begin() + 2, k_cache.shape.end());
386	    self_k_cache_size.insert(self_k_cache_size.begin(), local_batch_size);
387	
388	    // The resize of the value cache buffer by
389	    //   (local_batch_size, local_head_num, max_seq_len, size_per_head).
390	    std::vector<size_t> self_v_cache_size(v_cache.shape.begin() + 2, v_cache.shape.end());
391	    self_v_cache_size.insert(self_v_cache_size.begin(), local_batch_size);
392	
393	    if (use_shared_contexts) {
394	        // we use k_cache_layer_ and v_cache_layer_
395	        self_k_cache_size[3] = seq_len;
396	        self_v_cache_size[2] = seq_len;
397	    }
398	
399	    AttentionType attention_type =
400	        (input_tensors->isExist("linear_bias_slopes") || int8_mode_ == 2) ?
401	            getUnfusedAttentionType(attention_type_) :
402	            attention_type_;
403	    const bool is_unpadded_mha = isUnPaddedMHA(attention_type);
404	
405	    PUSH_RANGE("context_generation");
406	    for (uint ite = 0; ite < iteration_num; ite++) {
407	        size_t h_token_num = local_batch_size * seq_len;
408	        if (is_unpadded_mha) {
409	            const int* base_input_lengths =
410	                (use_shared_contexts ? compact_input_lengths_ : input_tensors->at("input_lengths").getPtr<int>());
411	            invokeGetPaddingOffsetAndCuSeqLens(h_pinned_token_num_ptr_,
412	                                               &h_token_num,
413	                                               padding_offset_,
414	                                               cu_seqlens_,
415	                                               base_input_lengths + ite * local_batch_size,
416	                                               local_batch_size,
417	                                               seq_len,
418	                                               stream_);
419	        }
420	
421	        for (uint l = 0; l < num_layer_; l++) {
422	            PUSH_RANGE(fmtstr("layer_%u", l));
423	            bool use_moe = std::find(moe_layer_index_.begin(), moe_layer_index_.end(), l) != moe_layer_index_.end();
424	            if (isValidLayerParallelId(l) == false) {
425	                continue;
426	            }
427	
428	            if (l == 0 && is_unpadded_mha) {
429	                PUSH_RANGE("remove padding");
430	                const T* base_input =
431	                    (use_shared_contexts ? compact_decoder_features_ : decoder_input_tensor.getPtr<T>());
432	                invokeRemovePadding(decoder_layer_output_,
433	                                    base_input + ite * local_batch_size * seq_len * hidden_units_,
434	                                    padding_offset_,
435	                                    h_token_num,
436	                                    hidden_units_,
437	                                    stream_);
438	                POP_RANGE;
439	            }
440	
441	            ParallelGptDecoderLayerWeight<T>* layer_weight = gpt_decoder_layer_weight->at(l);
442	
443	            T* decoder_input  = decoder_layer_output_;
444	            T* decoder_output = decoder_layer_output_;
445	            if (!is_unpadded_mha) {
446	                if (l == 0) {
447	                    decoder_input = use_shared_contexts ? compact_decoder_features_ : decoder_input_tensor.getPtr<T>();
448	                    decoder_input += ite * local_batch_size * seq_len * hidden_units_;
449	                }
450	                if (l == num_layer_ - 1) {
451	                    decoder_output = use_shared_contexts ? compact_decoder_features_ :
452	                                                           output_tensors->at("decoder_output").getPtr<T>();
453	                    decoder_output += ite * local_batch_size * seq_len * hidden_units_;
454	                }
455	            }
456	
457	            if (isFirstLayerParallelId(l) && pipeline_para_.rank_ != 0) {
458	                PUSH_RANGE("input communication");
459	                const int data_size = h_token_num * hidden_units_ / tensor_para_.world_size_;
460	                ftNcclRecv(decoder_input + data_size * tensor_para_.rank_,
461	                           data_size,
462	                           pipeline_para_.rank_ - 1,
463	                           pipeline_para_,
464	                           stream_);
465	                if (tensor_para_.world_size_ > 1) {
466	                    PUSH_RANGE("all gather");
467	                    ftNcclAllGather(decoder_input, decoder_input, data_size, tensor_para_.rank_, tensor_para_, stream_);
468	                    POP_RANGE;
469	                }
470	                POP_RANGE;
471	            }
472	
473	            PUSH_RANGE("pre-mha layernorm");
474	            if (layernorm_type_ == LayerNormType::pre_layernorm) {
475	                invokeGeneralLayerNorm(decoder_normed_input_,
476	                                       decoder_input,
477	                                       layer_weight->pre_layernorm_weights.gamma,
478	                                       layer_weight->pre_layernorm_weights.beta,
479	                                       layernorm_eps_,
480	                                       h_token_num,
481	                                       hidden_units_,
482	                                       const_cast<float*>(layer_weight->self_attention_weights.query_weight.scale),
483	                                       nullptr,
484	                                       /* dynamic_quant_ ? attention_query_dynamic_scale_ : nullptr, */
485	                                       int8_mode_,
486	                                       stream_);
487	            }
488	            sync_check_cuda_error();
489	            POP_RANGE;
490	
491	            const bool is_final = false;  // TODO(bhsueh) remove this flag
492	
493	            const T* attention_ptr =
494	                use_shared_contexts ? compact_attention_mask_ : input_tensors->at("attention_mask").getPtr<T>();
495	
496	            TensorMap self_attention_input_tensors{
497	                {"input_query",
498	                 Tensor{MEMORY_GPU,
499	                        activation_in_type,
500	                        {h_token_num, hidden_units_},
501	                        layernorm_type_ == LayerNormType::pre_layernorm ? decoder_normed_input_ : decoder_input}},
502	                {"attention_mask",
503	                 Tensor{MEMORY_GPU,
504	                        data_type,
505	                        {local_batch_size, 1, seq_len, seq_len},
506	                        attention_ptr + local_batch_size * ite * seq_len * seq_len}},
507	                {"attention_type", Tensor{MEMORY_CPU, TYPE_VOID, {1}, &attention_type}},
508	                {"is_final_layer", Tensor{MEMORY_CPU, TYPE_BOOL, {1}, &is_final}},
509	                {"layer_id", Tensor{MEMORY_CPU, TYPE_INT32, {(size_t)1}, &l}}};
510	
511	            if (is_unpadded_mha) {
512	                self_attention_input_tensors.insert("padding_offset",
513	                                                    Tensor{MEMORY_GPU, TYPE_INT32, {h_token_num}, padding_offset_});
514	                self_attention_input_tensors.insert(
515	                    "cu_seqlens", Tensor{MEMORY_GPU, TYPE_INT32, {size_t(local_batch_size + 1)}, cu_seqlens_});
516	            }
517	
518	            /* if (dynamic_quant_) { */
519	            /*     self_attention_input_tensors.insert("attention_query_dynamic_scale", */
520	            /*         Tensor{MEMORY_GPU, TYPE_FP32, {h_token_num}, attention_query_dynamic_scale_}); */
521	            /* } */
522	
523	            if (input_tensors->isExist("linear_bias_slopes")) {
524	                self_attention_input_tensors.insert("linear_bias_slopes", input_tensors->at("linear_bias_slopes"));
525	            }
526	
527	            // The key/value cache stride per batch.
528	            const size_t cache_stride_per_batch = hidden_units_ / tensor_para_.world_size_ * max_seq_len;
529	            // The key/value cache offset of the layer.
530	            const size_t cache_layer_offset =
531	                (l - getFirstLayerParallelId()) * request_batch_size * cache_stride_per_batch;
532	            // The key/value cache offset of the current local batch iteration.
533	            const size_t ite_cache_offset = ite * local_batch_size * cache_stride_per_batch;
534	            const size_t cache_offset     = cache_layer_offset + ite_cache_offset;
535	
536	            T* k_cache_ptr = use_shared_contexts ? k_cache_layer_ : k_cache.getPtrWithOffset<T>(cache_offset);
537	            T* v_cache_ptr = use_shared_contexts ? v_cache_layer_ : v_cache.getPtrWithOffset<T>(cache_offset);
538	
539	            TensorMap self_attention_output_tensors{
540	                {"hidden_features",
541	                 Tensor{MEMORY_GPU, activation_out_type, {h_token_num, hidden_units_}, self_attn_output_}},
542	                {"key_cache", Tensor{MEMORY_GPU, data_type, self_k_cache_size, k_cache_ptr}},
543	                {"value_cache", Tensor{MEMORY_GPU, data_type, self_v_cache_size, v_cache_ptr}}};
544	
545	            self_attention_layer_->forward(
546	                &self_attention_output_tensors, &self_attention_input_tensors, &layer_weight->self_attention_weights);
547	
548	            PUSH_RANGE("K/V cache clean");
549	            if (use_shared_contexts) {
550	                // Even with local batches, we must process the whole K/V caches as any
551	                // element in batch_idx_to_compact_idx may reference the local batch
552	                // we're processing. We also need to discard references that aren't in
553	                // that particular local batch.
554	                invokeUnCompactCaches(k_cache.getPtrWithOffset<T>(cache_layer_offset),
555	                                      v_cache.getPtrWithOffset<T>(cache_layer_offset),
556	                                      k_cache_layer_,
557	                                      v_cache_layer_,
558	                                      input_tensors->at("batch_to_compact_idx").getPtr<int>(),
559	                                      request_batch_size,  // batch_size (uncompact)
560	                                      v_cache.shape[2],    // local_head_num
561	                                      max_seq_len,
562	                                      seq_len,
563	                                      size_per_head_,
564	                                      local_batch_size,
565	                                      ite,
566	                                      stream_);
567	                sync_check_cuda_error();
568	            }
569	            POP_RANGE;
570	
571	            // the adapter after attention (only pre layernorm currently)
572	            PUSH_RANGE("post mha layernorm");
573	            if (has_adapters_) {
574	                invokeGenericActivation<IdentityActivation, T, T>(
575	                    self_attn_output_,
576	                    layer_weight->self_attention_weights.attention_output_weight.bias,
577	                    nullptr,
578	                    nullptr,
579	                    nullptr,
580	                    nullptr,
581	                    h_token_num,
582	                    hidden_units_,
583	                    0,
584	                    nullptr,
585	                    nullptr,
586	                    stream_);
587	
588	                TensorMap ffn_input_tensors(
589	                    {{"ffn_input", Tensor{MEMORY_GPU, data_type, {h_token_num, hidden_units_}, self_attn_output_}}});
590	                TensorMap ffn_output_tensors(
591	                    {{"ffn_output",
592	                      Tensor{MEMORY_GPU, data_type, {h_token_num, hidden_units_}, after_adapter_attn_output_}}});
593	
594	                ffn_layer_->resetInterSize(adapter_inter_size_ / tensor_para_.world_size_);
595	                ffn_layer_->forward(&ffn_output_tensors,
596	                                    &ffn_input_tensors,
597	                                    &gpt_decoder_layer_weight->at(l)->after_attention_adapter_weights);
598	            }
599	
600	            if (layernorm_type_ == LayerNormType::pre_layernorm) {
601	                invokeGeneralAddBiasResidualPreLayerNorm(
602	                    has_adapters_ ? after_adapter_attn_output_ : self_attn_output_,
603	                    normed_self_attn_output_,
604	                    has_adapters_ ? after_adapter_attn_output_ : self_attn_output_,
605	                    decoder_input,
606	                    has_adapters_ ? self_attn_output_ : nullptr,
607	                    layer_weight->self_attn_layernorm_weights.gamma,
608	                    layer_weight->self_attn_layernorm_weights.beta,
609	                    has_adapters_ ? layer_weight->after_attention_adapter_weights.output_weight.bias :
610	                                    layer_weight->self_attention_weights.attention_output_weight.bias,
611	                    layernorm_eps_,
612	                    h_token_num,
613	                    hidden_units_,
614	                    nullptr,
615	                    nullptr,
616	                    const_cast<float*>(layer_weight->ffn_weights.intermediate_weight.scale),
617	                    nullptr,  // NOTE (perkzz): dynamic_quant_ ? ffn_intermediate_dynamic_scale_ : nullptr,
618	                    int8_mode_,
619	                    stream_);
620	            }
621	            else if (layernorm_type_ == LayerNormType::post_layernorm) {
622	                invokeAddBiasResidualLayerNorm(after_adapter_attn_output_,
623	                                               decoder_input,
624	                                               has_adapters_ ?
625	                                                   layer_weight->after_attention_adapter_weights.output_weight.bias :
626	                                                   layer_weight->self_attention_weights.attention_output_weight.bias,
627	                                               layer_weight->pre_layernorm_weights.gamma,
628	                                               layer_weight->pre_layernorm_weights.beta,
629	                                               layernorm_eps_,
630	                                               h_token_num,
631	                                               hidden_units_,
632	                                               stream_);
633	            }
634	            sync_check_cuda_error();
635	            POP_RANGE;
636	
637	            T* ffn_output_ptr = has_adapters_ ? self_attn_output_ : decoder_output;
638	
639	            TensorMap ffn_input_tensors(
640	                {{"ffn_input",
641	                  Tensor{MEMORY_GPU,
642	                         activation_in_type,
643	                         {h_token_num, hidden_units_},
644	                         layernorm_type_ == LayerNormType::pre_layernorm ? normed_self_attn_output_ :
645	                                                                           after_adapter_attn_output_}}});
646	            TensorMap ffn_output_tensors;
647	            if (!use_moe) {
648	                ffn_output_tensors.insert(
649	                    "ffn_output",
650	                    Tensor{MEMORY_GPU, activation_out_type, {h_token_num, hidden_units_}, ffn_output_ptr});
651	            }
652	            else {
653	                ffn_input_tensors.insert("moe_k", Tensor{MEMORY_CPU, TYPE_UINT64, {1}, &moe_k_});
654	
655	                ffn_output_tensors.insert("ffn_output",
656	                                          Tensor{MEMORY_GPU,
657	                                                 activation_out_type,
658	                                                 {moe_k_ * h_token_num, hidden_units_},
659	                                                 has_adapters_ ? adapter_fc2_result_ : fc2_result_});
660	                ffn_output_tensors.insert(
661	                    "expert_scales", Tensor{MEMORY_GPU, activation_out_type, {h_token_num, moe_k_}, expert_scales_});
662	                ffn_output_tensors.insert(
663	                    "expanded_source_row_to_expanded_dest_row",
664	                    Tensor{MEMORY_GPU, TYPE_INT32, {h_token_num, moe_k_}, expanded_source_row_to_expanded_dest_row_});
665	                ffn_output_tensors.insert(
666	                    "expert_for_source_row",
667	                    Tensor{MEMORY_GPU, TYPE_INT32, {h_token_num, moe_k_}, expert_for_source_row_});
668	            }
669	
670	            ffn_layer_->resetInterSize(inter_size_ / tensor_para_.world_size_);
671	            ffn_layer_->forward(&ffn_output_tensors, &ffn_input_tensors, &layer_weight->ffn_weights);
672	
673	            // the adapter after ffn (only pre layernorm currently)
674	            PUSH_RANGE("post ffn");
675	            if (has_adapters_) {
676	                TensorMap ffn_input_tensors;
677	                TensorMap ffn_output_tensors;
678	                if (!use_moe) {
679	                    invokeGenericActivation<IdentityActivation, T, T>(ffn_output_ptr,
680	                                                                      layer_weight->ffn_weights.output_weight.bias,
681	                                                                      nullptr,
682	                                                                      nullptr,
683	                                                                      nullptr,
684	                                                                      nullptr,
685	                                                                      h_token_num,
686	                                                                      hidden_units_,
687	                                                                      0,
688	                                                                      nullptr,
689	                                                                      nullptr,
690	                                                                      stream_);
691	
692	                    ffn_input_tensors.insert(
693	                        "ffn_input", Tensor{MEMORY_GPU, data_type, {h_token_num, hidden_units_}, ffn_output_ptr});
694	                    ffn_output_tensors.insert(
695	                        "ffn_output", Tensor{MEMORY_GPU, data_type, {h_token_num, hidden_units_}, decoder_output});
696	                }
697	                else {
698	                    invokeGenericActivation<IdentityActivation, T, T>(adapter_fc2_result_,
699	                                                                      layer_weight->ffn_weights.output_weight.bias,
700	                                                                      nullptr,
701	                                                                      nullptr,
702	                                                                      nullptr,
703	                                                                      nullptr,
704	                                                                      moe_k_ * h_token_num,
705	                                                                      hidden_units_,
706	                                                                      0,
707	                                                                      nullptr,
708	                                                                      nullptr,
709	                                                                      stream_);
710	
711	                    ffn_input_tensors.insert(
712	                        "ffn_input",
713	                        Tensor{MEMORY_GPU, data_type, {moe_k_ * h_token_num, hidden_units_}, adapter_fc2_result_});
714	                    ffn_output_tensors.insert(
715	                        "ffn_output",
716	                        Tensor{MEMORY_GPU, data_type, {moe_k_ * h_token_num, hidden_units_}, fc2_result_});
717	                }
718	
719	                ffn_layer_->resetInterSize(adapter_inter_size_ / tensor_para_.world_size_);
720	                ffn_layer_->forward(&ffn_output_tensors, &ffn_input_tensors, &layer_weight->after_ffn_adapter_weights);
721	            }
722	
723	            if (!use_moe) {
724	                if (layernorm_type_ == LayerNormType::pre_layernorm) {
725	                    invokeAddBiasResidual(decoder_output,
726	                                          decoder_output,
727	                                          after_adapter_attn_output_,
728	                                          has_adapters_ ? ffn_output_ptr : nullptr,
729	                                          has_adapters_ ? layer_weight->after_ffn_adapter_weights.output_weight.bias :
730	                                                          layer_weight->ffn_weights.output_weight.bias,
731	                                          nullptr,
732	                                          nullptr,
733	                                          h_token_num,
734	                                          hidden_units_,
735	                                          stream_);
736	                }
737	                else if (layernorm_type_ == LayerNormType::post_layernorm) {
738	                    invokeAddBiasResidualLayerNorm(decoder_output,
739	                                                   after_adapter_attn_output_,
740	                                                   has_adapters_ ?
741	                                                       layer_weight->after_ffn_adapter_weights.output_weight.bias :
742	                                                       layer_weight->ffn_weights.output_weight.bias,
743	                                                   layer_weight->self_attn_layernorm_weights.gamma,
744	                                                   layer_weight->self_attn_layernorm_weights.beta,
745	                                                   layernorm_eps_,
746	                                                   h_token_num,
747	                                                   hidden_units_,
748	                                                   stream_);
749	                }
750	            }
751	            else {
752	                if (layernorm_type_ == LayerNormType::pre_layernorm) {
753	                    finalize_moe_routing_kernelLauncher(fc2_result_,
754	                                                        decoder_output,
755	                                                        after_adapter_attn_output_,
756	                                                        has_adapters_ ? ffn_output_ptr : nullptr,
757	                                                        has_adapters_ ?
758	                                                            layer_weight->after_ffn_adapter_weights.output_weight.bias :
759	                                                            layer_weight->ffn_weights.output_weight.bias,
760	                                                        expert_scales_,
761	                                                        expanded_source_row_to_expanded_dest_row_,
762	                                                        expert_for_source_row_,
763	                                                        h_token_num,
764	                                                        hidden_units_,
765	                                                        moe_k_,
766	                                                        stream_);
767	                }
768	                else if (layernorm_type_ == LayerNormType::post_layernorm) {
769	                    finalize_moe_routing_kernelLauncher(fc2_result_,
770	                                                        decoder_output,
771	                                                        after_adapter_attn_output_,
772	                                                        has_adapters_ ?
773	                                                            layer_weight->after_ffn_adapter_weights.output_weight.bias :
774	                                                            layer_weight->ffn_weights.output_weight.bias,
775	                                                        expert_scales_,
776	                                                        expanded_source_row_to_expanded_dest_row_,
777	                                                        expert_for_source_row_,
778	                                                        h_token_num,
779	                                                        hidden_units_,
780	                                                        moe_k_,
781	                                                        stream_);
782	                    invokeGeneralLayerNorm(decoder_output,
783	                                           decoder_output,
784	                                           layer_weight->self_attn_layernorm_weights.gamma,
785	                                           layer_weight->self_attn_layernorm_weights.beta,
786	                                           layernorm_eps_,
787	                                           h_token_num,
788	                                           hidden_units_,
789	                                           (float*)nullptr,
790	                                           0,
791	                                           stream_);
792	                }
793	            }
794	            sync_check_cuda_error();
795	            POP_RANGE;
796	            PUSH_RANGE("Nccl send");
797	            if (isLastLayerParallelId(l) == true && (pipeline_para_.rank_ != pipeline_para_.world_size_ - 1)) {
798	                const int data_size = h_token_num * hidden_units_ / tensor_para_.world_size_;
799	                ftNcclSend(decoder_output + data_size * tensor_para_.rank_,
800	                           data_size,
801	                           pipeline_para_.rank_ + 1,
802	                           pipeline_para_,
803	                           stream_);
804	            }
805	            POP_RANGE;
806	
807	            PUSH_RANGE("Rebuild padding");
808	            if ((l == num_layer_ - 1) && is_unpadded_mha) {
809	                T* base_ptr =
810	                    use_shared_contexts ? compact_decoder_features_ : output_tensors->at("decoder_output").getPtr<T>();
811	                invokeRebuildPadding(base_ptr + ite * local_batch_size * seq_len * hidden_units_,
812	                                     decoder_layer_output_,
813	                                     padding_offset_,
814	                                     h_token_num,
815	                                     head_num_ * size_per_head_,
816	                                     stream_);
817	            }
818	            POP_RANGE;
819	
820	            POP_RANGE;
821	        }
822	    }
823	    POP_RANGE;
824	
825	    PUSH_RANGE("uncompact outputs");
826	    if (use_shared_contexts) {
827	        invokeUnCompactOutputs(output_tensors->at("decoder_output").getPtr<T>(),
828	                               compact_decoder_features_,
829	                               input_tensors->at("batch_to_compact_idx").getPtr<int>(),
830	                               request_batch_size,  // batch
831	                               seq_len * hidden_units_,
832	                               stream_);
833	    }
834	    POP_RANGE;
835	
836	    PUSH_RANGE("last token hidden state lookup");
837	    // TODO(bhsueh) We could optimize this point by only computing the last token for the last layer
838	    invokeLookupHiddenStateOfLastToken(output_tensors->at("last_token_hidden_units").getPtr<T>(),
839	                                       output_tensors->at("decoder_output").getPtr<T>(),
840	                                       input_tensors->at("input_lengths").getPtr<int>(),
841	                                       seq_len,
842	                                       request_batch_size,
843	                                       hidden_units_,
844	                                       stream_);
845	    POP_RANGE;
846	    if (is_free_buffer_after_forward_ == true) {
847	        freeBuffer();
848	    }
849	    FT_LOG_DEBUG("%s stop", __PRETTY_FUNCTION__);
850	}
851	
852	template class ParallelGptContextDecoder<float>;
853	template class ParallelGptContextDecoder<half>;
854	#ifdef ENABLE_BF16
855	template class ParallelGptContextDecoder<__nv_bfloat16>;
856	#endif
857	
858	}  // namespace fastertransformer
