197	template<typename T>
198	void ParallelGptDecoder<T>::freeBuffer()
199	{
200	    if (is_allocate_buffer_) {
201	        FT_LOG_DEBUG(__PRETTY_FUNCTION__);
202	        allocator_->free((void**)(&decoder_layer_output_));
203	        allocator_->free((void**)(&decoder_normed_input_));
204	        allocator_->free((void**)(&self_attn_output_));
205	        allocator_->free((void**)(&normed_self_attn_output_));
206	        if (has_adapters_) {
207	            allocator_->free((void**)(&after_adapter_attn_output_));
208	            allocator_->free((void**)(&adapter_fc2_result_));
209	        }
210	        is_allocate_buffer_ = false;
211	
212	        allocator_->free((void**)(&expert_scales_));
213	        allocator_->free((void**)(&expanded_source_row_to_expanded_dest_row_));
214	        allocator_->free((void**)(&expert_for_source_row_));
215	        allocator_->free((void**)(&fc2_result_));
216	    }
217	}
