219	template<typename T>
220	bool ParallelGptDecoder<T>::isValidLayerParallelId(uint l)
221	{
222	    int local_num_layer = (int)(ceil(num_layer_ * 1.0f / pipeline_para_.world_size_));
223	    return l < num_layer_ && (l >= local_num_layer * pipeline_para_.rank_)
224	           && (l < local_num_layer * (pipeline_para_.rank_ + 1));
225	}
