227	template<typename T>
228	bool ParallelGptDecoder<T>::isFirstLayerParallelId(uint l)
229	{
230	    int local_num_layer = (int)(ceil(num_layer_ * 1.0f / pipeline_para_.world_size_));
231	    return l < num_layer_ && (l == local_num_layer * pipeline_para_.rank_);
232	}
233	
234	template<typename T>
235	bool ParallelGptDecoder<T>::isLastLayerParallelId(uint l)
236	{
237	    int local_num_layer = (int)(ceil(num_layer_ * 1.0f / pipeline_para_.world_size_));
238	    return l < num_layer_ && (l == local_num_layer * (pipeline_para_.rank_ + 1) - 1);
239	}
240	
241	template<typename T>
242	int ParallelGptDecoder<T>::getFirstLayerParallelId()
243	{
244	    int local_num_layer = (int)(ceil(num_layer_ * 1.0f / pipeline_para_.world_size_));
245	    return local_num_layer * pipeline_para_.rank_;
246	}
